410	/** Human-readable delegate target from the yield args (`{space, agent, action}` or positional). */
411	function delegateRef(args) {
412	  if (Array.isArray(args)) return args.slice(0, 3).filter(Boolean).join('/');
413	  if (args && typeof args === 'object') {
414	    const { space, agent, action } = args;
415	    return [space, agent, action].filter(Boolean).join('/');
416	  }
417	  return String(args);
418	}
419	
420	/** The prose THING showed the user: display() descriptors + the final assistant text. */
421	export function textOf(events) {
422	  const out = [];
423	  for (const e of events) {
424	    if (e.type === 'display') {
425	      const d = e.descriptor;
426	      const s =
427	        typeof d === 'string'
428	          ? d
429	          : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
430	      out.push(typeof s === 'string' ? s : JSON.stringify(s));
431	    }
432	  }
433	  return out.join('\n');
434	}
435	
436	/** The LAST thing THING displayed — its final reply for this turn (see `turn().lastText`). */
437	export function lastTextOf(events) {
438	  for (let i = events.length - 1; i >= 0; i--) {
439	    const e = events[i];
440	    if (e.type !== 'display') continue;
441	    const d = e.descriptor;
442	    const s =
443	      typeof d === 'string'
444	        ? d
445	        : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
446	    const out = typeof s === 'string' ? s : JSON.stringify(s);
447	    if (out && out.trim()) return out;
448	  }
449	  return '';
450	}
