    },
    end(chunk?: string | Buffer) {
      if (chunk !== undefined) out.body = Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk);
      out.ended = true;
      return this;
    },
  } as unknown as ServerResponse;
