  report.check(`…and declares a row type for "${legsTable}"`, new RegExp(legsTable.replace(/[-_]/g, '.?'), 'i').test(dts), dts.slice(0, 160).replace(/\n/g, ' '));

  const tree = await pod.fsTree().catch(() => ({ files: [] }));
