  report.check('the app still compiles after the restart', build?.built === true, `built:${build?.built}`);
  cp.acts.XIII = { passed: report.stepPassed };
  saveCheckpoint(cp);
}

// ═══ ACT XIV — A2: IT ACTUALLY RENDERS ═════════════════════════════════════════
if (ACTS.includes(14)) {
  report.step(
