    if (!meta) continue;
    traceAttachments.push({
      kind: meta.kind,
      url: uploadUrl(meta.id),
      mediaType: meta.mediaType,
      ...(meta.filename ? { filename: meta.filename } : {}),
      ...(meta.transcript ? { transcript: meta.transcript } : {}),
