export interface UploadMeta {
  id: string;
  kind: AttachmentKind;
  mediaType: string;
  filename?: string;
  /** Transcript text for audio uploads (what the model actually receives). */
  transcript?: string;
  /** Extracted plain text for a binary DOCUMENT (e.g. a PDF) whose bytes a text
