import { createEmitEventResolver, type ManualEmitDepth } from './emit-event.js';
import { transcribeAudio } from '../providers/transcribe.js';
import {
  resolveUploadsDir,
  saveUpload as saveUploadToDisk,
  readUploadMeta,
